final:
module top_module(
	input clk,
	input rst_n,
	output sink_sop,
	output sink_eop
);reg [10:0] packet_counter;

always@(posedge clk)
if(!rst_n)
	packet_counter<=11'd0;
else if(packet_counter>=11'd1030)
	packet_counter<=11'd0;
else
	packet_counter<=packet_counter+1'b1;


assign sink_sop=(packet_counter==11'd0)?1'b1:1'b0;

assign sink_eop=(packet_counter==11'd1023)?1'b1:1'b0;

endmodule
